import React, { useState, useEffect } from 'react';
import { Navigate, useLocation } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import axios from 'axios';

const ProtectedAdminRoute = ({ children }) => {
  const { currentUser, isAuthenticated, loading } = useAuth();
  const [isAdmin, setIsAdmin] = useState(false);
  const [checkingAdmin, setCheckingAdmin] = useState(true);
  const location = useLocation();

  useEffect(() => {
    const checkAdminStatus = async () => {
      if (!isAuthenticated || !currentUser) {
        console.log('Not authenticated or no current user. Redirecting to login.');
        setCheckingAdmin(false);
        return;
      }

      try {
        // 从localStorage获取token，与Login组件中使用的key保持一致
        const token = localStorage.getItem('token');
        console.log('Checking admin status with token:', token ? 'Token exists' : 'No token');
        
        if (!token) {
          console.log('No token found in localStorage');
          setIsAdmin(false);
          setCheckingAdmin(false);
          return;
        }
        
        console.log('Making request to /api/admin/check-admin');
        const response = await axios.get('/api/admin/check-admin', {
          headers: {
            Authorization: `Bearer ${token}`
          }
        });

        console.log('Admin check response:', response.data);
        if (response.data.isAdmin) {
          console.log('User confirmed as admin');
          setIsAdmin(true);
        } else {
          console.log('User is not an admin');
          setIsAdmin(false);
        }
      } catch (error) {
        console.error('管理员检查失败:', error);
        console.log('Admin check error response:', error.response?.data);
        setIsAdmin(false);
      } finally {
        setCheckingAdmin(false);
      }
    };

    checkAdminStatus();
  }, [isAuthenticated, currentUser]);

  if (loading || checkingAdmin) {
    return (
      <div className="flex items-center justify-center h-screen">
        <div className="text-xl font-semibold text-blue-900">
          正在验证管理员权限...
        </div>
      </div>
    );
  }

  if (!isAuthenticated) {
    console.log('Not authenticated, redirecting to login');
    return <Navigate to="/login" state={{ from: location }} replace />;
  }

  if (!isAdmin) {
    console.log('Not admin, redirecting to unauthorized');
    return <Navigate to="/unauthorized" state={{ from: location }} replace />;
  }

  console.log('Admin authorized, rendering protected content');
  return children;
};

export default ProtectedAdminRoute;
